import React from "react";

export default function ProfileScreen({ 
  user = { name: "", email: "", joinedDate: "" }, 
  onLogout,
  darkMode
}) {
  return (
    <div className={`px-6 pb-24 min-h-screen ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>
      <h1 className="text-2xl font-bold mb-6">Profile</h1>

      <div className={`p-6 rounded-xl border shadow-sm space-y-4 ${darkMode ? "bg-gray-800 border-gray-700" : "bg-white border-gray-100"}`}>
        <p>
          <span className="font-semibold">Name:</span> {user.name}
        </p>
        <p>
          <span className="font-semibold">Email:</span> {user.email}
        </p>
        <p>
          <span className="font-semibold">Joined:</span>{" "}
          {user.joinedDate && new Date(user.joinedDate).toLocaleDateString()}
        </p>
      </div>

      <button
        onClick={onLogout}
        className={`mt-6 w-full py-3 rounded-xl transition-colors ${
          darkMode
            ? "bg-red-700 hover:bg-red-600 text-white"
            : "bg-red-600 hover:bg-red-700 text-white"
        }`}
      >
        Logout
      </button>
    </div>
  );
}
